import{_ as e,o as a,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const f=JSON.parse('{"title":"东堂（王府井天主堂）","description":"","frontmatter":{},"headers":[],"relativePath":"religion/dongtang.md","filePath":"religion/dongtang.md","lastUpdated":null}'),n={name:"religion/dongtang.md"};function d(i,t,o,s,h,g){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="东堂-王府井天主堂" tabindex="-1">东堂（王府井天主堂） <a class="header-anchor" href="#东堂-王府井天主堂" aria-label="Permalink to &quot;东堂（王府井天主堂）&quot;">​</a></h1><blockquote><p>&quot;繁华王府井中的静谧圣地，新人最爱的婚纱摄影地。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>东堂，又称王府井天主堂、圣若瑟堂，位于北京市东城区王府井大街74号，是北京四大天主教堂之一。教堂始建于清顺治十二年（1655年），是罗马式建筑风格的典范，也是王府井地区的重要地标。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">7:00-20:00</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">免费</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">30分钟-1小时</td></tr><tr><td style="text-align:left;"><strong>弥撒时间</strong></td><td style="text-align:left;">平日6:30、18:00，周日6:30、8:00、10:00、18:00</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁1号线王府井站</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市东城区王府井大街74号</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="始建" tabindex="-1">始建 <a class="header-anchor" href="#始建" aria-label="Permalink to &quot;始建&quot;">​</a></h3><p>东堂始建于清顺治十二年（1655年），由葡萄牙籍耶稣会传教士利类思、安文思创建。最初是汤若望的宅邸，后改为教堂。</p><h3 id="重建" tabindex="-1">重建 <a class="header-anchor" href="#重建" aria-label="Permalink to &quot;重建&quot;">​</a></h3><p>清光绪二十六年（1900年），东堂在义和团运动中被焚毁。光绪三十年（1904年），用庚子赔款重建，形成今日所见的规模。</p><h3 id="近代" tabindex="-1">近代 <a class="header-anchor" href="#近代" aria-label="Permalink to &quot;近代&quot;">​</a></h3><p>1958年，东堂关闭。1980年，修复后重新开放，恢复宗教活动。2000年，王府井大街改造，教堂前的广场进行了扩建。</p><h2 id="建筑特色" tabindex="-1">建筑特色 <a class="header-anchor" href="#建筑特色" aria-label="Permalink to &quot;建筑特色&quot;">​</a></h2><h3 id="建筑风格" tabindex="-1">建筑风格 <a class="header-anchor" href="#建筑风格" aria-label="Permalink to &quot;建筑风格&quot;">​</a></h3><p>东堂采用罗马式建筑风格，具有典型的罗马式教堂特征：</p><ul><li><strong>厚重墙体</strong>：墙体厚重，给人坚实稳重之感</li><li><strong>半圆形拱</strong>：门窗采用半圆形拱</li><li><strong>钟楼</strong>：正面有一座钟楼</li><li><strong>十字架</strong>：顶部有十字架</li></ul><h3 id="外观" tabindex="-1">外观 <a class="header-anchor" href="#外观" aria-label="Permalink to &quot;外观&quot;">​</a></h3><p>东堂坐东朝西，正面朝向王府井大街。</p><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>墙体</strong></td><td style="text-align:left;">青砖砌筑，厚重坚实</td></tr><tr><td style="text-align:left;"><strong>屋顶</strong></td><td style="text-align:left;">中式大屋顶，覆盖琉璃瓦</td></tr><tr><td style="text-align:left;"><strong>钟楼</strong></td><td style="text-align:left;">正面有一座钟楼</td></tr><tr><td style="text-align:left;"><strong>高度</strong></td><td style="text-align:left;">钟楼高约20米</td></tr></tbody></table><h3 id="内部" tabindex="-1">内部 <a class="header-anchor" href="#内部" aria-label="Permalink to &quot;内部&quot;">​</a></h3><p>东堂内部空间不大，但庄严肃穆。</p><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>面积</strong></td><td style="text-align:left;">约500平方米</td></tr><tr><td style="text-align:left;"><strong>容量</strong></td><td style="text-align:left;">可容纳500余人</td></tr><tr><td style="text-align:left;"><strong>祭台</strong></td><td style="text-align:left;">主祭台供奉圣若瑟像</td></tr><tr><td style="text-align:left;"><strong>装饰</strong></td><td style="text-align:left;">内部装饰简洁典雅</td></tr></tbody></table><h2 id="王府井广场" tabindex="-1">王府井广场 <a class="header-anchor" href="#王府井广场" aria-label="Permalink to &quot;王府井广场&quot;">​</a></h2><h3 id="教堂广场" tabindex="-1">教堂广场 <a class="header-anchor" href="#教堂广场" aria-label="Permalink to &quot;教堂广场&quot;">​</a></h3><p>2000年王府井大街改造时，在教堂前修建了广场，成为王府井地区的一处休闲空间。</p><h3 id="婚纱摄影" tabindex="-1">婚纱摄影 <a class="header-anchor" href="#婚纱摄影" aria-label="Permalink to &quot;婚纱摄影&quot;">​</a></h3><p>教堂前广场是新人拍摄婚纱照的热门地点。白色的教堂、绿色的草坪、繁华的商业街，构成独特的景观。</p><h3 id="夜景" tabindex="-1">夜景 <a class="header-anchor" href="#夜景" aria-label="Permalink to &quot;夜景&quot;">​</a></h3><p>东堂夜景灯光很美，是王府井夜景的一部分。</p><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>教堂参观（约30分钟）</strong>：</p><p>王府井大街 → 教堂广场 → 进入教堂 → 内部参观 → 外部拍照</p><p><strong>结合王府井路线（约半天）</strong>：</p><p>王府井大街购物 → 东堂参观 → 王府井小吃街 → 百货大楼</p><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">站点</th></tr></thead><tbody><tr><td style="text-align:left;">地铁</td><td style="text-align:left;">1号线王府井站A口</td></tr><tr><td style="text-align:left;">公交</td><td style="text-align:left;">103路、104路、111路等王府井站</td></tr><tr><td style="text-align:left;">步行</td><td style="text-align:left;">从天安门步行约15分钟</td></tr></tbody></table><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>弥撒时间</strong>：可参加弥撒，体验宗教仪式</li><li><strong>婚纱摄影</strong>：广场是热门婚纱摄影地</li><li><strong>夜景美丽</strong>：晚上灯光很漂亮</li><li><strong>结合购物</strong>：可与王府井购物结合</li><li><strong>保持安静</strong>：弥撒时间请保持安静</li></ol><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">王府井大街</td><td style="text-align:center;">紧邻</td><td style="text-align:left;">繁华商业街</td></tr><tr><td style="text-align:left;">东方广场</td><td style="text-align:center;">步行5分钟</td><td style="text-align:left;">大型购物中心</td></tr><tr><td style="text-align:left;">百货大楼</td><td style="text-align:center;">步行5分钟</td><td style="text-align:left;">百年老店</td></tr><tr><td style="text-align:left;">天安门</td><td style="text-align:center;">步行15分钟</td><td style="text-align:left;">世界最大广场</td></tr><tr><td style="text-align:left;">故宫</td><td style="text-align:center;">步行20分钟</td><td style="text-align:left;">明清皇宫</td></tr></tbody></table><h2 id="文化价值" tabindex="-1">文化价值 <a class="header-anchor" href="#文化价值" aria-label="Permalink to &quot;文化价值&quot;">​</a></h2><p>东堂是北京四大天主教堂之一，是中西文化交流的重要见证。在繁华的王府井商业区，东堂以其宁静庄重的存在，提醒人们宗教信仰的力量。</p><p>东堂也是王府井地区的重要地标，是北京历史文化的组成部分。</p><hr><p><strong>📍 地址</strong>：北京市东城区王府井大街74号 <strong>📞 电话</strong>：010-65240643</p>',47)])])}const y=e(n,[["render",d]]);export{f as __pageData,y as default};
